package com.careeros.prompt.application;import org.springframework.core.io.ClassPathResource;import org.springframework.stereotype.Service;import java.nio.charset.StandardCharsets;import java.util.*;import java.util.regex.*;@Service public class PromptTemplateService{public static final String VERSION="1.0";private final String template;public PromptTemplateService(){try{template=new ClassPathResource("prompts/resume-tailoring-v1.txt").getContentAsString(StandardCharsets.UTF_8);}catch(Exception e){throw new IllegalStateException("Resume prompt template missing",e);}}public String render(Map<String,String>values){String result=template;for(var e:values.entrySet())result=result.replace("{"+e.getKey()+"}",Objects.toString(e.getValue(),""));Matcher m=Pattern.compile("\\{[a-z_]+}").matcher(result);if(m.find())throw new IllegalArgumentException("Unresolved prompt placeholder: "+m.group());return result;}}
